import React, { useState, useEffect } from 'react';
import '../assets/styles/Zoom.css';
import RefreshIcon from '@mui/icons-material/Refresh';
import CloseIcon from '@mui/icons-material/Close';
import axios from 'axios';

const Zoom = () => {
  const [showConfirm, setShowConfirm] = useState(false);
  const [contacts, setContacts] = useState([]);
  const [error, setError] = useState('');
  const [authenticated, setAuthenticated] = useState(false);

  // Verifică dacă utilizatorul este autentificat
  const checkAuthentication = () => {
    axios.get('/shortcuts/zoom/check-auth/')
      .then(response => {
        setAuthenticated(response.data.authenticated);
        if (response.data.authenticated) {
          fetchContacts();
        }
      })
      .catch(err => {
        console.error('Eroare la verificarea autentificării:', err);
      });
  };

  const fetchContacts = () => {
    axios.get('/shortcuts/zoom/get-contacts/')
      .then(response => {
        if (response.data.success) {
          setContacts(response.data.contacts);
        } else {
          setError('Nu s-a putut accesa lista de contacte');
        }
      })
      .catch(err => {
        setError('O eroare a apărut în timpul obținerii contactelor');
        console.error('Error:', err);
      });
  };

  useEffect(() => {
    checkAuthentication(); // Verifică autentificarea la inițializarea componentei
  }, []);

  const handleLogin = () => {
    window.location.href = '/shortcuts/zoom/oauth/login/';  // Redirectează utilizatorul către autentificare
  };

  return (
    <div className="zoom-container">
      <h1 className="title">Zoom</h1>
      
      {/* Dacă utilizatorul nu este autentificat, afișează butonul de autentificare */}
      {!authenticated ? (
        <button onClick={handleLogin} className="button login-button">
          Autentificare cu Zoom
        </button>
      ) : (
        <>
          {/* Afișează lista de contacte */}
          {error && <p className="error">{error}</p>}
          <ul className="contacts-list">
            {contacts.length > 0 ? (
              contacts.map((contact, index) => (
                <li key={index}>{contact.first_name} {contact.last_name}</li>
              ))
            ) : (
              <li>Nicio listă de contacte disponibilă</li>
            )}
          </ul>
        </>
      )}
    </div>
  );
};

export default Zoom;
